queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSpecies ?child ; p:hasAgroforestry_Systems ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agroforestry_Systems } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSpecies ?child ; p:hasAgroforestry_Systems ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agroforestry_Systems } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?system_name ?name WHERE {
  ?system_species a :System_Species .
  ?species a :Species .
  ?system_species p:hasSpecies ?species .
  ?agroforestry_systems a :Agroforestry_Systems .
  ?system_species p:hasAgroforestry_Systems ?agroforestry_systems .
  ?agroforestry_systems p:name ?system_name .
  ?species p:name ?name .
} }
}
